    47→        { success: false, error: "Organization not found" },
    48→        { status: 401 }
    49→      );
    50→    }
    51→
    52→    // Parse query parameters
    53→    const searchParams = Object.fromEntries(request.nextUrl.searchParams);
    54→    const params = querySchema.parse(searchParams);
    55→
    56→    // Get brand IDs for this organization
    57→    const orgBrands = await db
    58→      .select({ id: brands.id })
    59→      .from(brands)
    60→      .where(and(eq(brands.organizationId, orgId), eq(brands.isActive, true)));
    61→
    62→    const brandIds = orgBrands.map((b) => b.id);
    63→
    64→    if (brandIds.length === 0) {
    65→      return NextResponse.json({
    66→        success: true,
    67→        data: [],
    68→        meta: {
    69→          total: 0,
    70→          limit: params.limit,
    71→          offset: params.offset,
    72→          timestamp: new Date().toISOString(),
    73→        },
    74→      });
    75→    }
    76→
    77→    // Build query conditions
    78→    const conditions = [inArray(recommendations.brandId, brandIds)];
    79→
    80→    if (params.brandId) {
    81→      conditions.push(eq(recommendations.brandId, params.brandId));
    82→    }
    83→
    84→    if (params.category) {
    85→      conditions.push(eq(recommendations.category, params.category));
    86→    }
    87→
    88→    if (params.status) {
    89→      conditions.push(eq(recommendations.status, params.status));
    90→    }
    91→
    92→    if (params.priority) {
    93→      conditions.push(eq(recommendations.priority, params.priority));
    94→    }
    95→
    96→    if (params.effort) {
    97→      conditions.push(eq(recommendations.effort, params.effort));
    98→    }
    99→
   100→    if (params.impact) {
   101→      conditions.push(eq(recommendations.impact, params.impact));
   102→    }
   103→
   104→    if (params.source) {
   105→      conditions.push(eq(recommendations.source, params.source));
   106→    }
   107→
   108→    if (params.dueBefore) {
   109→      conditions.push(lte(recommendations.dueDate, new Date(params.dueBefore)));
   110→    }
   111→
   112→    if (params.dueAfter) {
   113→      conditions.push(gte(recommendations.dueDate, new Date(params.dueAfter)));
   114→    }
   115→
   116→    // Execute query
   117→    const recommendationsList = await db
   118→      .select()
   119→      .from(recommendations)
   120→      .where(and(...conditions))
   121→      .orderBy(desc(recommendations.createdAt))
   122→      .limit(params.limit)
   123→      .offset(params.offset);
   124→
   125→    // Get total count for pagination
   126→    const totalResult = await db
   127→      .select({ count: recommendations.id })
   128→      .from(recommendations)
   129→      .where(and(...conditions));
   130→
   131→    // Auto-detect: Mark "Review Recommendations" step as complete
   132→    if (recommendationsList.length > 0 && orgId) {
