     1→/**
     2→ * Recommendations Generate API (F106-F107)
     3→ * POST /api/recommendations/generate - Generate recommendations for a brand
     4→ */
     5→
     6→import { NextRequest, NextResponse } from "next/server";
     7→import { auth } from "@clerk/nextjs/server";
     8→import { db } from "@/lib/db";
     9→import { brands, audits, brandMentions } from "@/lib/db/schema";
    10→import { eq, and, desc } from "drizzle-orm";
    11→import { z } from "zod";
    12→import {
    13→  generateRecommendations,
    14→  type MonitorData,
    15→  type AuditData,
    16→} from "@/lib/recommendations";
    17→
    18→// Request schema
    19→const generateRequestSchema = z.object({
    20→  brandId: z.string().min(1, "Brand ID is required"),
    21→  includeMonitor: z.boolean().default(true),
    22→  includeAudit: z.boolean().default(true),
    23→  maxRecommendations: z.number().min(1).max(100).default(50),
    24→  minConfidence: z.number().min(0).max(100).default(30),
    25→});
    26→
    27→export async function POST(request: NextRequest) {
    28→  try {
    29→    const { userId, orgId } = await auth();
    30→
    31→    if (!userId) {
    32→      return NextResponse.json(
    33→        { error: "Unauthorized" },
    34→        { status: 401 }
    35→      );
    36→    }
    37→
    38→    // Parse and validate request
    39→    const body = await request.json();
    40→    const {
    41→      brandId,
    42→      includeMonitor,
    43→      includeAudit,
    44→      maxRecommendations,
    45→      minConfidence,
    46→    } = generateRequestSchema.parse(body);
    47→
    48→    // Verify brand belongs to user's org
    49→    const brand = await db.query.brands.findFirst({
    50→      where: and(
    51→        eq(brands.id, brandId),
    52→        orgId ? eq(brands.organizationId, orgId) : undefined
    53→      ),
    54→    });
    55→
    56→    if (!brand) {
    57→      return NextResponse.json(
    58→        { error: "Brand not found" },
    59→        { status: 404 }
    60→      );
    61→    }
    62→
    63→    // Gather monitor data if requested
    64→    const monitorDataArray: MonitorData[] = [];
    65→    if (includeMonitor) {
    66→      const recentMentions = await db.query.brandMentions.findMany({
    67→        where: eq(brandMentions.brandId, brandId),
    68→        orderBy: [desc(brandMentions.timestamp)],
    69→        limit: 100,
    70→      });
    71→
    72→      // Group by platform
    73→      const platformGroups = new Map<string, typeof recentMentions>();
    74→      for (const result of recentMentions) {
    75→        const platform = result.platform;
    76→        if (!platformGroups.has(platform)) {
    77→          platformGroups.set(platform, []);
    78→        }
    79→        platformGroups.get(platform)!.push(result);
    80→      }
    81→
    82→      // Convert to MonitorData format
    83→      for (const [platform, results] of platformGroups) {
    84→        const mentions = results.map((r) => ({
    85→          id: r.id,
    86→          platform: r.platform,
    87→          query: r.query,
    88→          mentioned: r.position !== null, // Brand is mentioned if position is set
    89→          position: r.position ?? undefined,
    90→          context: r.response ?? undefined,
    91→          sentiment: r.sentiment as "positive" | "neutral" | "negative" | undefined,
    92→          timestamp: r.timestamp,
    93→        }));
    94→
    95→        // Calculate sentiment
    96→        const sentimentCounts = { positive: 0, neutral: 0, negative: 0 };
    97→        for (const m of mentions) {
    98→          if (m.sentiment) {
    99→            sentimentCounts[m.sentiment]++;
   100→          } else {
   101→            sentimentCounts.neutral++;
   102→          }
   103→        }
   104→        const total = mentions.length || 1;
   105→        const sentimentScore =
   106→          (sentimentCounts.positive - sentimentCounts.negative) / total;
   107→
   108→        monitorDataArray.push({
   109→          brandId,
   110→          platform,
   111→          mentions,
   112→          sentiment: {
   113→            overall:
   114→              sentimentScore > 0.2
   115→                ? "positive"
   116→                : sentimentScore < -0.2
   117→                ? "negative"
   118→                : "neutral",
   119→            score: sentimentScore,
   120→            breakdown: {
   121→              positive: sentimentCounts.positive / total,
   122→              neutral: sentimentCounts.neutral / total,
   123→              negative: sentimentCounts.negative / total,
   124→            },
   125→          },
   126→          competitors: [], // Would need competitor data from monitor
   127→          timestamp: new Date(),
   128→        });
   129→      }
   130→    }
   131→
   132→    // Gather audit data if requested
   133→    let auditData: AuditData | null = null;
   134→    if (includeAudit) {
   135→      const latestAudit = await db.query.audits.findFirst({
   136→        where: and(
   137→          eq(audits.brandId, brandId),
   138→          eq(audits.status, "completed")
   139→        ),
   140→        orderBy: [desc(audits.completedAt)],
   141→      });
   142→
   143→      if (latestAudit) {
   144→        auditData = {
   145→          brandId,
   146→          url: latestAudit.url,
   147→          overallScore: latestAudit.overallScore ?? 0,
   148→          categoryScores: (latestAudit.categoryScores ?? []).map((cs) => ({
   149→            category: cs.category,
   150→            score: cs.score,
   151→            maxScore: cs.maxScore,
   152→            issues: cs.issues,
   153→          })),
   154→          issues: (latestAudit.issues ?? []).map((issue) => ({
   155→            id: issue.id,
   156→            category: issue.category,
   157→            severity: issue.severity,
   158→            title: issue.title,
   159→            description: issue.description,
   160→            recommendation: issue.recommendation,
   161→            impact: issue.impact,
   162→          })),
   163→          timestamp: latestAudit.completedAt ?? new Date(),
   164→        };
   165→      }
   166→    }
   167→
   168→    // Generate recommendations
   169→    const recommendations = await generateRecommendations(
   170→      brandId,
   171→      monitorDataArray,
   172→      auditData,
   173→      {
   174→        maxRecommendations,
   175→        minConfidence,
   176→      }
   177→    );
   178→
   179→    // Group by priority
   180→    const grouped = {
   181→      critical: recommendations.filter((r) => r.priority === "critical"),
   182→      high: recommendations.filter((r) => r.priority === "high"),
   183→      medium: recommendations.filter((r) => r.priority === "medium"),
   184→      low: recommendations.filter((r) => r.priority === "low"),
   185→    };
   186→
   187→    return NextResponse.json({
   188→      success: true,
   189→      brandId,
   190→      generatedAt: new Date().toISOString(),
   191→      summary: {
   192→        total: recommendations.length,
   193→        critical: grouped.critical.length,
   194→        high: grouped.high.length,
   195→        medium: grouped.medium.length,
   196→        low: grouped.low.length,
   197→      },
   198→      sources: {
   199→        monitorPlatforms: monitorDataArray.length,
   200→        auditIncluded: auditData !== null,
   201→      },
   202→      recommendations: recommendations.map((r) => ({
   203→        id: r.id,
   204→        source: r.source,
   205→        category: r.category,
   206→        priority: r.priority,
   207→        priorityScore: r.priorityScore,
   208→        title: r.title,
   209→        description: r.description,
   210→        impact: r.impact,
   211→        effort: r.effort,
   212→        urgency: r.urgency,
   213→        confidence: r.confidence,
   214→        actionItems: r.actionItems,
   215→        aiPlatforms: r.aiPlatforms,
   216→      })),
   217→      grouped,
   218→    });
   219→  } catch (error) {
   220→    if (error instanceof z.ZodError) {
   221→      return NextResponse.json(
   222→        { error: "Validation error", details: error.issues },
   223→        { status: 400 }
   224→      );
   225→    }
   226→
   227→    return NextResponse.json(
   228→      {
   229→        error: "Failed to generate recommendations",
   230→        details: error instanceof Error ? error.message : "Unknown error",
   231→      },
   232→      { status: 500 }
   233→    );
   234→  }
   235→}
