   660→ * Calculate competitive advantage score based on competitor data
   661→ */
   662→export function calculateCompetitiveAdvantageScore(
   663→  competitors: CompetitorMetrics[],
   664→  platforms: PlatformVisibility[],
   665→  targetedPlatforms: string[]
   666→): number {
   667→  if (competitors.length === 0 || platforms.length === 0) {
   668→    return 50; // Default when no competitor data
   669→  }
   670→
   671→  // Calculate average brand mention rate on targeted platforms
   672→  const relevantPlatforms = platforms.filter((p) =>
   673→    targetedPlatforms.some(
   674→      (tp) => tp.toLowerCase() === p.name.toLowerCase()
   675→    )
   676→  );
   677→
   678→  if (relevantPlatforms.length === 0) {
   679→    return 50;
   680→  }
   681→
   682→  const brandAvgMentionRate = relevantPlatforms.reduce(
   683→    (sum, p) => sum + p.mentionRate, 0
   684→  ) / relevantPlatforms.length;
   685→
   686→  // Calculate average competitor mention rate
   687→  const competitorAvgMentionRate = competitors.reduce(
   688→    (sum, c) => sum + c.mentionRate, 0
   689→  ) / competitors.length;
   690→
   691→  // Calculate competitive gap (how much behind competitors)
   692→  const competitiveGap = Math.max(0, competitorAvgMentionRate - brandAvgMentionRate);
   693→
   694→  // Score based on competitive gap
   695→  // Gap > 40% = critical competitive disadvantage (80-100)
   696→  // Gap 20-40% = significant gap (60-79)
   697→  // Gap 10-20% = moderate gap (40-59)
   698→  // Gap < 10% = minor gap (0-39)
   699→  if (competitiveGap > 40) {
   700→    return Math.min(100, 80 + (competitiveGap - 40) * 0.5);
   701→  } else if (competitiveGap > 20) {
   702→    return 60 + (competitiveGap - 20);
   703→  } else if (competitiveGap > 10) {
   704→    return 40 + (competitiveGap - 10) * 2;
   705→  } else {
   706→    return competitiveGap * 4;
   707→  }
   708→}
