    71→      userMessage,
    72→      mergedConfig
    73→    );
    74→    return response;
    75→  } catch (primaryError) {
    76→    // If fallback is enabled and primary fails, try secondary
    77→    if (mergedConfig.fallbackEnabled) {
    78→      const fallbackProvider: LLMProvider =
    79→        mergedConfig.provider === "claude" ? "openai" : "claude";
    80→
    81→      console.warn(
    82→        `Primary provider ${mergedConfig.provider} failed, falling back to ${fallbackProvider}:`,
    83→        primaryError instanceof Error ? primaryError.message : primaryError
    84→      );
    85→
    86→      try {
    87→        const response = await sendToProvider(
    88→          fallbackProvider,
    89→          systemPrompt,
    90→          userMessage,
    91→          { ...mergedConfig, provider: fallbackProvider }
    92→        );
    93→        return response;
    94→      } catch (fallbackError) {
